import{_ as i,o as e,c as a,ag as t}from"./chunks/framework.BbyMWZAR.js";const c=JSON.parse('{"title":"事件循环（Event Loop）的阶段","description":"","frontmatter":{"title":"事件循环（Event Loop）的阶段","difficulty":"medium","tags":["事件循环","libuv","nextTick"],"estimate":20},"headers":[],"relativePath":"domains/nodejs/qa/qa-03-event-loop.md","filePath":"domains/nodejs/qa/qa-03-event-loop.md","lastUpdated":1783504823000}'),n={name:"domains/nodejs/qa/qa-03-event-loop.md"};function l(o,s,r,h,d,p){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="问答-03-进阶-事件循环-event-loop-的阶段" tabindex="-1">问答 03（进阶）：事件循环（Event Loop）的阶段 <a class="header-anchor" href="#问答-03-进阶-事件循环-event-loop-的阶段" aria-label="Permalink to &quot;问答 03（进阶）：事件循环（Event Loop）的阶段&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>详细描述 Node.js 事件循环的各个阶段。它和浏览器的事件循环有什么不同？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>事件循环阶段（libuv，按顺序循环）</strong></p><ol><li><strong>timers</strong>：执行到期的 <code>setTimeout</code> / <code>setInterval</code> 回调。</li><li><strong>pending callbacks</strong>：执行上一轮延迟到本轮的某些系统回调（如某些 TCP 错误）。</li><li><strong>idle, prepare</strong>：内部使用。</li><li><strong>poll（轮询）</strong>：核心阶段。计算应阻塞多久，检索新的 I/O 事件并执行其回调（如文件读完、socket 有数据）。若无定时器且队列空，会在此阻塞等待 I/O。</li><li><strong>check</strong>：执行 <code>setImmediate</code> 回调。</li><li><strong>close callbacks</strong>：执行 <code>close</code> 事件回调（如 <code>socket.on(&#39;close&#39;)</code>）。</li></ol><p><strong>微任务队列</strong></p><ul><li><strong>每个阶段之间</strong>都会清空微任务队列，顺序：先 <code>process.nextTick</code> 队列，再 Promise 的 <code>then/catch/finally</code>（microtask）。</li><li><code>process.nextTick</code> 优先级 <strong>高于</strong> Promise microtask。</li></ul><p><strong>与浏览器的区别</strong></p><ul><li>浏览器没有 <code>setImmediate</code>（非标准）和 <code>process.nextTick</code>，宏任务/微任务模型相对简单：一个宏任务执行完就清空所有微任务，然后可能渲染。</li><li>浏览器每个宏任务后清微任务；Node（新版本行为已趋近浏览器）在每个「阶段」或每个宏任务后清微任务，早期版本会在阶段切换时批量清。</li><li>浏览器有渲染管线（requestAnimationFrame 等），Node 没有。</li></ul><h2 id="追问-1-下面代码的输出顺序是什么-为什么" tabindex="-1">追问 1：下面代码的输出顺序是什么？为什么？ <a class="header-anchor" href="#追问-1-下面代码的输出顺序是什么-为什么" aria-label="Permalink to &quot;追问 1：下面代码的输出顺序是什么？为什么？&quot;">​</a></h2><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;1&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;2&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setImmediate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;3&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">then</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;4&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">process.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nextTick</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;5&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;6&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>答</strong>：</p><ul><li>同步先执行：<code>1</code>、<code>6</code>。</li><li>同步栈清空后清微任务：<code>nextTick</code> 优先 → <code>5</code>，再 Promise → <code>4</code>。</li><li>然后进入事件循环阶段。<code>setTimeout(0)</code> 与 <code>setImmediate</code> 在<strong>主模块顶层</strong>的先后不确定（取决于进程启动耗时），常见结果是 <code>2</code> 先或 <code>3</code> 先都可能。</li><li>因此稳定输出前缀是：<code>1 6 5 4</code>，之后 <code>2 3</code> 或 <code>3 2</code>。</li><li>若把这两行放进一个 I/O 回调里（如 <code>fs.readFile</code> 回调），则一定是 <code>setImmediate(3)</code> 先于 <code>setTimeout(2)</code>，因为 I/O 回调在 poll 阶段，紧接着就是 check 阶段。</li></ul><h2 id="追问-2-什么是「事件循环阻塞」-如何监控和排查" tabindex="-1">追问 2：什么是「事件循环阻塞」？如何监控和排查？ <a class="header-anchor" href="#追问-2-什么是「事件循环阻塞」-如何监控和排查" aria-label="Permalink to &quot;追问 2：什么是「事件循环阻塞」？如何监控和排查？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>指主线程执行了长时间同步代码（大循环、同步大文件读、复杂正则、<code>JSON.parse</code> 超大对象），导致事件循环无法进入下一阶段，所有回调延迟、请求超时。</li><li><strong>监控</strong>：<code>perf_hooks.monitorEventLoopDelay()</code> 采集事件循环延迟直方图；APM 工具（如 clinic doctor）；<code>--prof</code> 生成火焰图。</li><li><strong>排查</strong>：定位长同步任务，改为异步/流式，拆分到 <code>worker_threads</code>，或用分片（把大循环拆成多次 <code>setImmediate</code>）。</li></ul><h2 id="追问-3-setinterval-为什么可能出现「回调堆积」或时间不准" tabindex="-1">追问 3：<code>setInterval</code> 为什么可能出现「回调堆积」或时间不准？ <a class="header-anchor" href="#追问-3-setinterval-为什么可能出现「回调堆积」或时间不准" aria-label="Permalink to &quot;追问 3：\`setInterval\` 为什么可能出现「回调堆积」或时间不准？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><code>setInterval</code> 只保证「至少间隔 N 毫秒后加入 timers 队列」，不保证准时执行。若事件循环繁忙或回调本身耗时超过间隔，回调会延迟，且不会「补偿」——但可能出现回调排队，逻辑上像堆积。</li><li>若回调是异步的且耗时超过间隔，多个回调可能并发执行，产生竞态。</li><li>更稳妥的做法：用「递归 <code>setTimeout</code>」——在上一次回调完成后再安排下一次，保证串行且间隔可控。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/en/docs/guides/event-loop-timers-and-nexttick" target="_blank" rel="noreferrer">Node.js: Event Loop</a>：六个阶段、<code>nextTick</code> 与 Promise 微任务队列的官方说明。</li><li><a href="https://docs.libuv.org/en/latest/design.html" target="_blank" rel="noreferrer">libuv Design Overview</a>：poll 阶段阻塞与线程池分工，理解 libuv 与 Node 事件循环的边界。</li><li><a href="https://nodejs.org/api/timers.html" target="_blank" rel="noreferrer">Node.js: Timers</a>：timers 阶段 API 与最小延迟行为。</li></ul>`,23)])])}const E=i(n,[["render",l]]);export{c as __pageData,E as default};
